#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int F, H, W;
        scanf("%d %d %d", &F, &H, &W);
        int *P = (int*)malloc(F * sizeof(int));
        for (int i = 0; i < F; i++) {
            scanf("%d", &P[i]);
        }
        qsort(P, F, sizeof(int), compare);
        int minArea = H * P[0];
        for (int i = 1; i < F; i++) {
            int area = H * (P[i] - P[i-1]);
            if (area < minArea) {
                minArea = area;
            }
        }
        int area = H * (W - P[F-1]);
        if (area < minArea) {
            minArea = area;
        }
        printf("%d\n", minArea);
        free(P);
    }
    return 0;
}

