import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int F = sc.nextInt();
            int H = sc.nextInt();
            int W = sc.nextInt();
            int[] P = new int[F];
            for (int i = 0; i < F; i++) {
                P[i] = sc.nextInt();
            }
            Arrays.sort(P);
            int minArea = H * P[0];
            for (int i = 1; i < F; i++) {
                int area = H * (P[i] - P[i-1]);
                if (area < minArea) {
                    minArea = area;
                }
            }
            int area = H * (W - P[F-1]);
            if (area < minArea) {
                minArea = area;
            }
            System.out.println(minArea);
        }
    }
}

