    for (let j = 1; j < F; j++) {
        const area = H * (P[j] - P[j-1]);
        if (area < minArea) {
            minArea = area;
        }
    }
    const area = H * (W - P[P.length - 1]);
    if (area < minArea) {
        minArea = area;
    }
    console.log(minArea);
}

